}

/**
 * Wires the detail grid's default sort: price ascending as the primary sort,
 * with unpriced/declined rows pushed to the bottom. Mutates the matching
 * colDef in place. The comparator reads the row's `Price` directly so it is
 * independent of the column's colId/field/valueGetter.
 */
private applyDefaultPriceSort(colHeaders: any[]): void {
  if (!Array.isArray(colHeaders)) return;
  const isPriceCol = (c: any) => c?.colId === 'quote_price' || c?.colId === 'price';
  // Prefer a visible price column; fall back to any price column.
  const priceCol =
    colHeaders.find(c => isPriceCol(c) && c?.hide !== true) ||
    colHeaders.find(c => isPriceCol(c));
  if (!priceCol) return;

  priceCol.sort = 'asc';
  priceCol.sortIndex = 0;
  priceCol.comparator = (_valueA: any, _valueB: any, nodeA: any, nodeB: any) => {
    const aBottom = this.isUnpricedOrDeclined(nodeA?.data);
    const bBottom = this.isUnpricedOrDeclined(nodeB?.data);
    if (aBottom && bBottom) return 0;
    if (aBottom) return 1;
    if (bBottom) return -1;
    return this.toPrice(nodeA?.data?.['Price']) - this.toPrice(nodeB?.data?.['Price']);
  };
}

