.detail-renderer-container {
  display: flex;
  flex-direction: column;
  height: 100%;
  background-color: #edf6ff;
  padding: 20px;
  overflow: visible; // Allow context menu to be visible

  // 1. Grid Wrapper
  .detail-grid-wrapper {
    flex-grow: 1;
    width: 100%;
    min-height: 200px; // Ensure visibility
    border: 1px solid #9fa8da;
    border-bottom: none;
    box-sizing: border-box;
    overflow: visible; // Allow context menu to be visible

    &.vendor-view {
      height: auto !important;
      min-height: 0;
      flex-grow: 0;
    }

    ag-grid-angular {
      width: 100%;
      height: 100%;
    }
  }

  // 2. Actions Toolbar (Barbell Layout)
  .detail-actions-toolbar {
    flex-shrink: 0;
    display: flex;
    justify-content: space-between;
    align-items: center;
    padding: 16px 24px;
    background-color: white;
    border: 1px solid #9fa8da;
    border-top: 1px solid $border-color;
    box-sizing: border-box;

    .action-group-left,
    .action-group-right {
      display: flex;
      align-items: center;
      gap: 12px;
    }

    // Button Overrides for strict Designflow compliance
    button[mat-flat-button],
    button[mat-stroked-button],
    button[mat-raised-button] {
      height: 48px; // Strict height
      border-radius: $border-radius;
      font-weight: 500;
      letter-spacing: 0.5px;

      mat-icon {
        margin-right: 8px;
      }
    }

    button[mat-stroked-button] {
      border-color: $border-color;
      color: $text-secondary; // Secondary text color by default

      &:hover {
        border-color: $primary;
        color: $primary;
        background: rgba($primary, 0.04);
      }

      &.mat-warn {
        color: #f44336;

        &:hover {
          border-color: #f44336;
          background: rgba(244, 67, 54, 0.04);
        }
      }
    }

    button[mat-flat-button] {
      background-color: $primary;
      color: white;
    }

  }
}

// Global AG Grid Overrides for this component context
// Scope these styles to only affect the detail grid, not the master grid
::ng-deep .detail-grid-wrapper {
  .ag-root-wrapper {
    border: none !important;
    border-radius: 0 !important;
  }

  .ag-header {
    background-color: $soft-grey !important;
    border-bottom: 1px solid $border-color !important;
    height: 48px !important;
    min-height: 48px !important;
  }

  .ag-header-cell-text {
    color: $dark-slate;
    font-weight: 600;
    font-size: 13px;
  }

  .ag-row {
    border-bottom-color: $border-color !important;

    &.ag-row-selected {
      background-color: rgba($primary, 0.05) !important;
    }
  }

  // Status colors from original file but modernized/softened if needed
  .responded {
    background-color: rgba(76, 175, 80, 0.1) !important; // Soft Green
  }

  .passed {
    background-color: rgba(244, 67, 54, 0.1) !important; // Soft Red
  }

  .empty {
    background-color: transparent !important;
  }

  // Stale price flagged for re-quote: orange cell highlight. Targets .ag-cell so
  // it paints over the row-level responded/passed/empty backgrounds.
  .ag-cell.requote-requested-cell {
    background-color: #FFA500 !important;
  }

  // Input fixes
  .mat-mdc-input-element {
    height: 100%;
  }
}

