// Designflow Brand Tokens
$primary: #D81B60;
$dark-slate: #1a202e;
$soft-grey: #f8f9fa;
$text-secondary: #546e7a;
$border-color: #e9ecef;
$border-radius: 6px;

:host {
  display: block;
  height: 100%;
  width: 100%;
}

.detail-renderer-container {
  display: flex;
  flex-direction: column;
  height: 100%;
  background-color: #edf6ff;
  padding: 10px;
  overflow: visible; // Allow context menu to be visible

  // 1. Grid Wrapper
  .detail-grid-wrapper {
    flex-grow: 1;
    width: 100%;
    min-height: 200px; // Ensure visibility
    border: 1px solid #9fa8da;
    border-bottom: none;
    box-sizing: border-box;
    overflow: visible; // Allow context menu to be visible

    &.vendor-view {
      height: auto !important;
      min-height: 0;
      flex-grow: 0;
    }

    ag-grid-angular {
      width: 100%;
      height: 100%;
    }
  }

  // 2. Actions Toolbar (Barbell Layout)
  .detail-actions-toolbar {
    flex-shrink: 0;
    display: flex;
    justify-content: space-between;
    align-items: center;
    padding: 6px 16px;
    background-color: white;
    border: 1px solid #9fa8da;
    border-top: 1px solid $border-color;
    box-sizing: border-box;

    .action-group-left,
    .action-group-right {
      display: flex;
      align-items: center;
      gap: 12px;
    }

