/* --- Main Toolbar Layout --- */
.rfq-toolbar {
  display: flex;
  align-items: center;
  padding: 0px 16px;
  background-color: #fff;
  border-bottom: 1px solid #e0e0e0;
  height: auto;
  min-height: 55px; /* Sufficient height for inputs */
  box-sizing: border-box;
  flex-wrap: wrap; /* Allow wrapping on small screens */
  gap: 12px;
}

.toolbar-left, .toolbar-right {
  display: flex;
  align-items: center;
  gap: 12px;
}

.toolbar-spacer {
  flex: 1 1 auto;
}

.admin-group, .filter-group, .view-group, .utility-group, .bulk-status-group {
  display: flex;
  align-items: center;
  gap: 8px;
}

/* --- Input & Field Styling --- */

.compact-field {
  width: 150px;
}

.wide-field {
  width: 180px;
}

.bulk-status-field {
  width: 135px;
}

/* Override Mat-Field to look like a box */
::ng-deep .mat-mdc-form-field-flex {
  align-items: center !important;
  background-color: #fff !important;
}

::ng-deep .mat-mdc-text-field-wrapper {
  background-color: #fff !important;
}

/* Center the select value text vertically within the form field */
::ng-deep .toolbar-field {
  .mat-mdc-form-field-infix {
    display: flex;
    align-items: center;
    min-height: 40px;
  }

  .mat-mdc-select {
    display: flex;
    align-items: center;
    margin-bottom: 3px;
  }

  .mat-mdc-select-value {
    display: flex;
    align-items: center;
    margin-bottom: 3px;
  }
}

/* --- Button Styling --- */

/* Primary Pink Button */
.create-btn {
  background-color: #D81B60 !important; /* Brand Pink */
  color: #fff !important;
  border-radius: 4px;
  height: 40px;
  padding: 0 20px;
  font-weight: 500;
  box-shadow: 0 2px 5px rgba(0,0,0,0.1);

  mat-icon {
    margin-right: 6px;
  }
}

/* Secondary Ghost/Outline Button */
.secondary-btn {
  background-color: #fff !important;
  color: #37474f !important;
  border: 1px solid #cfd8dc !important;
  height: 40px;
  border-radius: 4px;
  min-width: unset; /* Allows icon-only buttons to be square-ish */
  padding: 0 12px;

  mat-icon {
    color: #546e7a;
    font-size: 20px;
    width: 20px;
    height: 20px;
    margin: 0;
  }

  span {
    margin-left: 6px;
  }
}

/* --- View Dropdown Internals --- */
.view-dropdown-actions {
  padding: 8px;
  border-top: 1px solid #eee;
  display: flex;
  flex-direction: column;
  gap: 8px;
}

.view-btn-group {
  display: flex;
  justify-content: space-between;
}

.new-view-input {
  display: flex;
  gap: 8px;
  align-items: center;

  .view-input {
    border: 1px solid #ccc;
    padding: 6px;
    border-radius: 4px;
    width: 100%;
  }
}

/* --- Utilities --- */
.overlay-spinner {
  position: fixed;
  top: 0; left: 0;
  width: 100vw; height: 100vh;
  background: rgba(255, 255, 255, 0.7);
  display: flex;
  align-items: center;
  justify-content: center;
  z-index: 9999;
}

/* Responsive adjustments */
@media (max-width: 1000px) {
  .rfq-toolbar {
    height: auto;
    padding: 12px;
  }
  .toolbar-spacer {
    display: none; /* Stack items on small screens */
  }
  .toolbar-right {
    width: 100%;
    justify-content: space-between;
    flex-wrap: wrap;
  }
}

::ng-deep .ag-full-width-row {
  background-color: #7f97a1 !important;
}

::ng-deep .ag-paging-panel {
  justify-content: center !important;
}

::ng-deep .add-new-product-dialog .mat-mdc-dialog-container {
  height: auto !important;
  max-height: calc(100vh - 48px) !important;
  width: min(1350px, calc(100vw - 48px)) !important;
}

::ng-deep .add-new-product-dialog .mat-mdc-dialog-surface {
  max-height: calc(100vh - 48px) !important;
  overflow: hidden !important;
}

/* Allow header text to wrap but limit to 3 lines */
::ng-deep .ag-header-cell-label {
