  border-radius: 4px;
  height: 40px;
  padding: 0 20px;
  font-weight: 500;
  box-shadow: 0 2px 5px rgba(0,0,0,0.1);

  mat-icon {
    margin-right: 6px;
  }
}

/* Secondary Ghost/Outline Button */
.secondary-btn {
  background-color: #fff !important;
  color: #37474f !important;
  border: 1px solid #cfd8dc !important;
  height: 40px;
  border-radius: 4px;
  min-width: unset; /* Allows icon-only buttons to be square-ish */
  padding: 0 12px;

  mat-icon {
    color: #546e7a;
    font-size: 20px;
    width: 20px;
    height: 20px;
    margin: 0;
  }

  span {
    margin-left: 6px;
  }
}

/* --- View Dropdown Internals --- */
.view-dropdown-actions {
  padding: 8px;
  border-top: 1px solid #eee;
  display: flex;
  flex-direction: column;
  gap: 8px;
}

.view-btn-group {
  display: flex;
  justify-content: space-between;
}

.new-view-input {
  display: flex;
  gap: 8px;
  align-items: center;

  .view-input {
    border: 1px solid #ccc;
    padding: 6px;
    border-radius: 4px;
    width: 100%;
  }
}

/* --- Utilities --- */
.overlay-spinner {
  position: fixed;
  top: 0; left: 0;
  width: 100vw; height: 100vh;
  background: rgba(255, 255, 255, 0.7);
  display: flex;
  align-items: center;
  justify-content: center;
  z-index: 9999;
}

/* Responsive adjustments */
@media (max-width: 1000px) {
  .rfq-toolbar {
    height: auto;
    padding: 12px;
  }
  .toolbar-spacer {
    display: none; /* Stack items on small screens */
  }
  .toolbar-right {
    width: 100%;
    justify-content: space-between;
    flex-wrap: wrap;
  }
}

::ng-deep .ag-full-width-row {
  background-color: #7f97a1 !important;
}

::ng-deep .ag-paging-panel {
  justify-content: center !important;
}

::ng-deep .add-new-product-dialog .mat-mdc-dialog-container {
  height: auto !important;
  max-height: calc(100vh - 48px) !important;
  width: min(1350px, calc(100vw - 48px)) !important;
}

::ng-deep .add-new-product-dialog .mat-mdc-dialog-surface {
  max-height: calc(100vh - 48px) !important;
  overflow: hidden !important;
}

/* Allow header text to wrap but limit to 3 lines */
::ng-deep .ag-header-cell-label {
  white-space: normal !important;
  line-height: 1.2;
  text-align: center; /* optional */
}

/* Ensure header text spans full width but limit height to 3 lines */
::ng-deep .ag-header-cell-text {
  white-space: normal !important;
  max-height: 3.6em !important; /* 1.2em line-height * 3 lines = 3.6em */
  overflow: hidden !important;
  display: -webkit-box !important;
  -webkit-line-clamp: 3 !important;
  -webkit-box-orient: vertical !important;
}

/* Column Group Header Colors */
::ng-deep .ag-header-cell.group-header-gen-fob {
  background-color: #F1F8FF !important; /* Lighter Blue */

  .ag-header-cell-text,
  .ag-header-cell-label {
    color: #1976D2 !important;
  }
}

::ng-deep .ag-header-cell.group-header-gen-poe {
  background-color: #F3E5F5 !important; /* Light Purple */

  .ag-header-cell-text,
  .ag-header-cell-label {
    color: #7B1FA2 !important;
  }
}

::ng-deep .ag-header-cell.group-header-gen-whse {
  background-color: #E8F5E9 !important; /* Light Green */

  .ag-header-cell-text,
  .ag-header-cell-label {
    color: #388E3C !important;
  }
}

::ng-deep .ag-header-cell.group-header-gen-mddp {
  background-color: #FFF8F0 !important; /* Lighter Orange */

  .ag-header-cell-text,
  .ag-header-cell-label {
    color: #F57C00 !important;
  }
}

::ng-deep .ag-header-cell.group-header-lic-poe {
  background-color: #FCE4EC !important; /* Light Pink */

  .ag-header-cell-text,
  .ag-header-cell-label {
    color: #C2185B !important;
  }
}

::ng-deep .ag-header-cell.group-header-lic-fob {
  background-color: #E0F2F1 !important; /* Light Teal */

  .ag-header-cell-text,
  .ag-header-cell-label {
    color: #00796B !important;
  }
}

::ng-deep .ag-header-cell.group-header-lic-mddp {
  background-color: #FFF3CD !important; /* Light Amber */

  .ag-header-cell-text,
  .ag-header-cell-label {
    color: #856404 !important;
  }
}

::ng-deep .ag-header-cell.group-header-lic-whse {
  background-color: #F8E1F5 !important; /* Lighter Lavender */

  .ag-header-cell-text,
  .ag-header-cell-label {
    color: #6A1B9A !important;
  }
}

/* Flash background color */
::ng-deep .ag-cell-data-changed {
  background-color: #FFE4C4 !important; /* Bisque */
}

/* Smooth fade-out animation */
::ng-deep .ag-cell-data-changed-animation {
  transition: background-color 0.6s ease-out;
}

/* Set fixed heights for header rows to prevent layout issues - sized for 3-line wrapping,
   then reduced ~15% (60 -> 51, 50 -> 43) to tighten the grid vertically. */
::ng-deep .grid-wrapper .ag-header-row {
  height: 51px !important;
}

::ng-deep .grid-wrapper .ag-header-row-floating-filter {
  height: 43px !important;
}

/* Add margin-bottom to floating filter textboxes for cleaner appearance */
::ng-deep .grid-wrapper .ag-floating-filter-input input,
::ng-deep .grid-wrapper .ag-text-field-input,
::ng-deep .grid-wrapper .ag-floating-filter-body input {
  margin-bottom: 10px !important;
}

/* Prevent detail cell renderer CSS from affecting master grid header */
::ng-deep .grid-wrapper .ag-header {
  position: relative !important;
  /* Don't set z-index here as it can interfere with context menu */
}

/* Ensure context menu is visible above everything */
::ng-deep .ag-menu,
::ng-deep .ag-popup-child {
  z-index: 10000 !important;
}

/* Fix filter list text color in right sidebar - override pink theme's headerTextColor */
::ng-deep .ag-filter-toolpanel-group-level-0-header,
::ng-deep .ag-filter-toolpanel-group-level-0-header .ag-group-title,
::ng-deep .ag-filter-toolpanel-group-level-0-header .ag-group-title-bar,
::ng-deep .ag-filter-toolpanel-group-level-0-header-icon,
::ng-deep .ag-filter-toolpanel-group-level-0-header span,
::ng-deep .ag-filter-toolpanel-group-title {
  color: #7E2E84 !important; /* rgb(126, 46, 132) - purple color for better visibility */
}


.grid-wrapper {
  position: relative;
}

/* Chips overlay: float active filter/sort chips into the right side of the AG Grid
   row-group panel bar so they share that row instead of consuming their own row. */
::ng-deep .grid-wrapper .group-panel-chips-overlay {
  position: absolute;
  top: 0;
  right: 40px;   /* clear the reset-grid button (icon 25px + 8px inset + gap) */
  z-index: 4;
  pointer-events: auto;

  .chips {
    border: none;
    box-shadow: none;
    border-radius: 0;
    background: transparent;
    padding: 4px 8px;
    min-height: 42px;       /* matches AG Grid Alpine group-panel bar height */
    max-height: 42px;
    overflow: hidden;
    flex-wrap: nowrap;
  }
}

/* Give the group panel drop zone room on the right so dragged-column chips
   don't slide under the filter chips overlay. */
::ng-deep .grid-wrapper .ag-column-drop-horizontal {
  padding-right: 240px;
}

::ng-deep .grid-wrapper {
  /* Add borders to all cells with explicit color */
  .ag-cell {
    border-right: 1px solid #e0e0e0 !important;
  }
  .ag-cell-focus
  {
    border: 1.5px solid #2196f3 !important;
  }
  /* Highlight the entire row that contains the focused cell */
  .ag-row-focus {
    background-color: rgba(33, 150, 243, 0.07) !important;
  }
}

::ng-deep .tech-pack-cell {
  display: flex;
  align-items: center;
  gap: 4px;
  min-width: 0;
  height: 100%;
}

::ng-deep .tech-pack-cell__text {
  flex: 1 1 auto;
  min-width: 0;
  overflow: hidden;
  text-overflow: ellipsis;
  white-space: nowrap;
  color: #1565c0;
}

::ng-deep .tech-pack-cell__button {
  flex: 0 0 auto;
  border: 1px solid #cfd8dc;
  border-radius: 4px;
  background: #fff;
  color: #37474f;
  cursor: pointer;
  font: inherit;
  font-size: 11px;
  line-height: 18px;
  padding: 0 5px;
}

::ng-deep .tech-pack-cell__button:disabled {
  color: #9e9e9e;
  cursor: default;
}

/* Custom status bar: remove the gray bar/line above the status bar (AG Grid top border) */
::ng-deep .grid-wrapper .ag-status-bar {
  border-top: 1px solid #e0e0e0 !important;
}

