describe('detail grid default price sort', () => {
  test('isUnpricedOrDeclined sinks blank, zero, negative and declined rows', () => {
    const { component } = createComponent();
    const c = component as any;
    // bottom rows
    expect(c.isUnpricedOrDeclined(undefined)).toBe(true);
    expect(c.isUnpricedOrDeclined({ Price: null })).toBe(true);
    expect(c.isUnpricedOrDeclined({ Price: '' })).toBe(true);
    expect(c.isUnpricedOrDeclined({ Price: 0 })).toBe(true);
    expect(c.isUnpricedOrDeclined({ Price: '0' })).toBe(true);
    expect(c.isUnpricedOrDeclined({ Price: -5 })).toBe(true);
    expect(c.isUnpricedOrDeclined({ Price: 12, req_status: 1 })).toBe(true); // declined to quote
    // priced rows stay
    expect(c.isUnpricedOrDeclined({ Price: 12 })).toBe(false);
    expect(c.isUnpricedOrDeclined({ Price: '12.5', req_status: 2 })).toBe(false);
  });

  test('quote_price column gets ascending default sort as primary, name secondary', () => {
    const { component } = createComponent();
    const c = component as any;
    c.role = 'admin';
    c.masterColumnDefs = [];
    c.configureDetailColumnHeaders([
      { colId: 'name', field: 'Name' },
      { colId: 'quote_price', field: 'Price' },
    ]);

    const priceCol = c.colDefs.find((col: any) => col.colId === 'quote_price');
    const nameCol = c.colDefs.find((col: any) => col.colId === 'name');
    expect(priceCol.sort).toBe('asc');
    expect(priceCol.sortIndex).toBe(0);
    expect(nameCol.sort).toBe('asc');
    expect(nameCol.sortIndex).toBe(1);
  });

  test('legacy "price" colId also receives the default price sort', () => {
    const { component } = createComponent();
    const c = component as any;
    const cols = [{ colId: 'name' }, { colId: 'price', field: 'Price' }];
    c.applyDefaultPriceSort(cols);

