test('quote_price column is the only default sort; name has no default sort', () => {
  const { component } = createComponent();
  const c = component as any;
  c.role = 'admin';
  c.masterColumnDefs = [];
  c.configureDetailColumnHeaders([
    { colId: 'name', field: 'Name' },
    { colId: 'quote_price', field: 'Price' },
  ]);

  const priceCol = c.colDefs.find((col: any) => col.colId === 'quote_price');
  const nameCol = c.colDefs.find((col: any) => col.colId === 'name');
  expect(priceCol.sort).toBe('asc');
  expect(priceCol.sortIndex).toBe(0);
  // Name no longer carries a secondary sort, so the grid shows a single sort
  // (price) with no multi-sort order badge on the headers.
  expect(nameCol.sort).toBeUndefined();
  expect(nameCol.sortIndex).toBeUndefined();
});

